mapper.select:
SELECT
    p.id, p.line_no, p.product_name, p.product_no, p.type, p.remark, p.version, p.deploy_at, p.is_valid, p.is_delete, p.create_at,
    pp.value_type, pp.value, pp.period_type
FROM product p
LEFT JOIN product_period pp ON p.product_no = pp.product_no


        p.line_no = #{param.lineNo}


        AND p.type = #{param.type}


        AND p.product_name like CONCAT(#{param.productName}, '%')


        AND p.product_no = #{param.productNo}


        AND p.is_valid = #{param.isValid}

    AND p.is_delete = 0 AND pp.is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM product p
LEFT JOIN product_period pp ON p.product_no = pp.product_no


        p.line_no = #{param.lineNo}


        AND p.type = #{param.type}


        AND p.product_name like CONCAT(#{param.productName}, '%')


        AND p.product_no = #{param.productNo}


        AND p.is_valid = #{param.isValid}

    AND p.is_delete = 0 AND pp.is_delete = 0

SELECT p.product_no, p.product_name, p.remark, pe.value_type, pe.value, pe.period_type, pe.version FROM product p LEFT JOIN product_period pe ON p.product_no = pe.product_no WHERE p.product_no IN
#{no}
AND p.is_delete = 0 AND pe.is_delete = 0
